#include &lt;iostream&gt;#include &lt;fstream&gt;#include &lt;sstream&gt;#include &lt;string&gt;std::string readEntireFile(const std::string&amp; filename) &#123;    // 方法2：使用stringstream    std::ifstream file(filename);    std::stringstream buffer;    if (!file.is_open()) &#123;        return &quot;&quot;;  // 返回空字符串表示失败    &#125;    buffer &lt;&lt; file.rdbuf();  // 读取整个文件    file.close();    return buffer.str();&#125;// 或者更现代的方式std::string readEntireFile2(const std::string&amp; filename) &#123;    std::ifstream file(filename, std::ios::ate);  // ate: 直接到文件末尾    if (!file.is_open()) &#123;        return &quot;&quot;;    &#125;    size_t fileSize = file.tellg();  // 获取文件大小    file.seekg(0);  // 回到开头    std::string content;    content.resize(fileSize);  // 预分配空间    file.read(&amp;content[0], fileSize);  // 直接读取到string    file.close();    return content;&#125;
