#include &lt;iostream&gt;#include &lt;fstream&gt;#include &lt;vector&gt;// 读取二进制文件（如图片、模型）std::vector&lt;char&gt; readBinaryFile(const std::string&amp; filename) &#123;    // 以二进制模式打开    std::ifstream file(filename, std::ios::binary | std::ios::ate);    if (!file.is_open()) &#123;        throw std::runtime_error(&quot;无法打开文件: &quot; + filename);    &#125;    // 获取文件大小    std::streamsize size = file.tellg();    file.seekg(0, std::ios::beg);    // 读取到vector    std::vector&lt;char&gt; buffer(size);    if (!file.read(buffer.data(), size)) &#123;        throw std::runtime_error(&quot;读取文件失败: &quot; + filename);    &#125;    file.close();    return buffer;&#125;​读取配置文件（CSV/键值对）#include &lt;iostream&gt;#include &lt;fstream&gt;#include &lt;sstream&gt;#include &lt;map&gt;#include &lt;vector&gt;// 读取CSV文件std::vector&lt;std::vector&lt;std::string&gt;&gt; readCSV(const std::string&amp; filename) &#123;    std::ifstream file(filename);    std::vector&lt;std::vector&lt;std::string&gt;&gt; data;    std::string line;    while (std::getline(file, line)) &#123;        std::vector&lt;std::string&gt; row;        std::stringstream lineStream(line);        std::string cell;        while (std::getline(lineStream, cell, &#x27;,&#x27;)) &#123;  // 逗号分隔            row.push_back(cell);        &#125;        data.push_back(row);    &#125;    return data;&#125;// 读取键值对配置文件std::map&lt;std::string, std::string&gt; readConfig(const std::string&amp; filename) &#123;    std::ifstream file(filename);    std::map&lt;std::string, std::string&gt; config;    std::string line;    while (std::getline(file, line)) &#123;        // 跳过注释和空行        if (line.empty() || line[0] == &#x27;#&#x27;) &#123;            continue;        &#125;        size_t pos = line.find(&#x27;=&#x27;);        if (pos != std::string::npos) &#123;            std::string key = line.substr(0, pos);            std::string value = line.substr(pos + 1);            // 去除空格            key.erase(0, key.find_first_not_of(&quot; \\t&quot;));            key.erase(key.find_last_not_of(&quot; \\t&quot;) + 1);            value.erase(0, value.find_first_not_of(&quot; \\t&quot;));            value.erase(value.find_last_not_of(&quot; \\t&quot;) + 1);            config[key] = value;        &#125;    &#125;    return config;&#125;​错误处理最佳实践#include &lt;iostream&gt;#include &lt;fstream&gt;#include &lt;string&gt;#include &lt;system_error&gt;  // C++11错误处理class FileReader &#123;private:    std::string filename_;public:    explicit FileReader(const std::string&amp; filename) : filename_(filename) &#123;&#125;    // 方法1：返回bool表示成功/失败    bool readToString(std::string&amp; content) &#123;        std::ifstream file(filename_);        if (!file) &#123;            std::cerr &lt;&lt; &quot;无法打开文件: &quot; &lt;&lt; filename_ &lt;&lt; std::endl;            return false;        &#125;        std::stringstream buffer;        buffer &lt;&lt; file.rdbuf();        content = buffer.str();        return true;    &#125;    // 方法2：抛出异常    std::string readOrThrow() &#123;        std::ifstream file(filename_);        if (!file) &#123;            throw std::runtime_error(&quot;无法打开文件: &quot; + filename_);        &#125;        std::stringstream buffer;        buffer &lt;&lt; file.rdbuf();        return buffer.str();    &#125;    // 方法3：使用std::error_code（现代C++）    std::string readWithError(std::error_code&amp; ec) &#123;        std::ifstream file(filename_);        if (!file) &#123;            ec = std::make_error_code(std::errc::no_such_file_or_directory);            return &quot;&quot;;        &#125;        std::stringstream buffer;        buffer &lt;&lt; file.rdbuf();        ec.clear();  // 清除错误码        return buffer.str();    &#125;&#125;;
