 实用工具函数集合
#include &lt;iostream&gt;#include &lt;fstream&gt;#include &lt;sstream&gt;#include &lt;string&gt;#include &lt;vector&gt;namespace FileUtils &#123;    // 检查文件是否存在    bool fileExists(const std::string&amp; path) &#123;        std::ifstream file(path);        return file.good();    &#125;    // 获取文件大小    size_t getFileSize(const std::string&amp; filename) &#123;        std::ifstream file(filename, std::ios::binary | std::ios::ate);        if (!file.is_open()) return 0;        return file.tellg();    &#125;    // 读取前N行    std::vector&lt;std::string&gt; readFirstNLines(const std::string&amp; filename, int n) &#123;        std::ifstream file(filename);        std::vector&lt;std::string&gt; lines;        std::string line;        for (int i = 0; i &lt; n &amp;&amp; std::getline(file, line); i++) &#123;            lines.push_back(line);        &#125;        return lines;    &#125;    // 统计文件行数    int countLines(const std::string&amp; filename) &#123;        std::ifstream file(filename);        if (!file.is_open()) return -1;        int count = 0;        std::string line;        while (std::getline(file, line)) &#123;            count++;        &#125;        return count;    &#125;    // 查找文件中是否包含特定文本    bool containsText(const std::string&amp; filename, const std::string&amp; searchText) &#123;        std::ifstream file(filename);        std::string line;        while (std::getline(file, line)) &#123;            if (line.find(searchText) != std::string::npos) &#123;                return true;            &#125;        &#125;        return false;    &#125;&#125;
 指针
 一、指针基础概念
1.1 什么是指针指针是一个变量，其值为另一个变量的内存地址。int var = 10;      // 普通整型变量int* ptr = &amp;var;   // ptr是指向var的指针​1.2 指针声明和初始化// 声明指针int* p1;       // 指向int的指针double* p2;    // 指向double的指针char* p3;      // 指向char的指针// 初始化指针int x = 5;int* ptr = &amp;x;  // &amp; 取地址运算符// 空指针（推荐使用nullptr，C++11以后）int* p4 = nullptr;  // 现代C++int* p5 = NULL;     // 传统C/C++int* p6 = 0;        // 字面量0
 二、指针基本操作
2.1 取地址和间接访问int value = 42;int* ptr = &amp;value;    // ptr保存value的地址cout &lt;&lt; &quot;value的值: &quot; &lt;&lt; value &lt;&lt; endl;      // 42cout &lt;&lt; &quot;value的地址: &quot; &lt;&lt; &amp;value &lt;&lt; endl;   // 0x7ffeeb5c...cout &lt;&lt; &quot;ptr的值: &quot; &lt;&lt; ptr &lt;&lt; endl;          // 与&amp;value相同cout &lt;&lt; &quot;ptr指向的值: &quot; &lt;&lt; *ptr &lt;&lt; endl;     // 42，*是解引用运算符// 通过指针修改变量*ptr = 100;cout &lt;&lt; &quot;修改后value的值: &quot; &lt;&lt; value &lt;&lt; endl;  // 100​2.2 指针运算int arr[5] = &#123;10, 20, 30, 40, 50&#125;;int* p = arr;  // p指向数组第一个元素cout &lt;&lt; *p &lt;&lt; endl;        // 10cout &lt;&lt; *(p + 1) &lt;&lt; endl;  // 20，指针加法cout &lt;&lt; *(p + 2) &lt;&lt; endl;  // 30p++;  // 移动到下一个元素cout &lt;&lt; *p &lt;&lt; endl;        // 20// 指针比较int* p1 = &amp;arr[0];int* p2 = &amp;arr[3];if (p1 &lt; p2) &#123;    cout &lt;&lt; &quot;p1在p2之前&quot; &lt;&lt; endl;&#125;
 三、指针与数组
3.1 数组名即指针int numbers[5] = &#123;1, 2, 3, 4, 5&#125;;// 数组名是指向第一个元素的指针cout &lt;&lt; numbers &lt;&lt; endl;    // 数组首地址cout &lt;&lt; &amp;numbers[0] &lt;&lt; endl; // 与numbers相同// 访问数组元素cout &lt;&lt; numbers[2] &lt;&lt; endl;      // 3cout &lt;&lt; *(numbers + 2) &lt;&lt; endl;  // 3，等价于numbers[2]// 遍历数组的三种方式// 1. 使用下标for (int i = 0; i &lt; 5; i++) &#123;    cout &lt;&lt; numbers[i] &lt;&lt; &quot; &quot;;&#125;// 2. 使用指针算术for (int i = 0; i &lt; 5; i++) &#123;    cout &lt;&lt; *(numbers + i) &lt;&lt; &quot; &quot;;&#125;// 3. 使用指针变量int* ptr = numbers;for (int i = 0; i &lt; 5; i++) &#123;    cout &lt;&lt; *ptr++ &lt;&lt; &quot; &quot;;&#125;​3.2 指针数组 vs 数组指针// 指针数组：数组的元素是指针int a = 1, b = 2, c = 3;int* ptrArr[3] = &#123;&amp;a, &amp;b, &amp;c&#125;;// 数组指针：指向数组的指针int arr[5] = &#123;1, 2, 3, 4, 5&#125;;int (*arrPtr)[5] = &amp;arr;  // 指向整个数组的指针// 访问cout &lt;&lt; (*arrPtr)[2] &lt;&lt; endl;  // 3
 四、指针与函数
4.1 指针作为函数参数（传地址）// 通过指针修改实参void swap(int* a, int* b) &#123;    int temp = *a;    *a = *b;    *b = temp;&#125;int main() &#123;    int x = 5, y = 10;    cout &lt;&lt; &quot;交换前: x=&quot; &lt;&lt; x &lt;&lt; &quot;, y=&quot; &lt;&lt; y &lt;&lt; endl;    swap(&amp;x, &amp;y);    cout &lt;&lt; &quot;交换后: x=&quot; &lt;&lt; x &lt;&lt; &quot;, y=&quot; &lt;&lt; y &lt;&lt; endl;    return 0;&#125;​4.2 数组作为函数参数// 三种等价形式void printArray(int arr[], int size) &#123;    for (int i = 0; i &lt; size; i++) &#123;        cout &lt;&lt; arr[i] &lt;&lt; &quot; &quot;;    &#125;&#125;void printArray(int* arr, int size) &#123;  // 更明确的指针形式    for (int i = 0; i &lt; size; i++) &#123;        cout &lt;&lt; arr[i] &lt;&lt; &quot; &quot;;    &#125;&#125;// 使用int main() &#123;    int data[5] = &#123;1, 2, 3, 4, 5&#125;;    printArray(data, 5);  // 数组名自动转换为指针    return 0;&#125;​4.3 函数指针// 函数原型int add(int a, int b) &#123;    return a + b;&#125;int multiply(int a, int b) &#123;    return a * b;&#125;int main() &#123;    // 声明函数指针    int (*funcPtr)(int, int);    // 指向add函数    funcPtr = &amp;add;  // 或直接 funcPtr = add;    cout &lt;&lt; &quot;10 + 5 = &quot; &lt;&lt; funcPtr(10, 5) &lt;&lt; endl;    // 指向multiply函数    funcPtr = multiply;    cout &lt;&lt; &quot;10 * 5 = &quot; &lt;&lt; funcPtr(10, 5) &lt;&lt; endl;    return 0;&#125;
 五、动态内存管理
5.1 new和delete操作符// 单个变量的动态分配int* p = new int;     // 分配一个int*p = 42;cout &lt;&lt; *p &lt;&lt; endl;delete p;             // 释放内存p = nullptr;          // 避免野指针// 数组的动态分配int size = 5;int* arr = new int[size];  // 分配数组for (int i = 0; i &lt; size; i++) &#123;    arr[i] = i * 10;&#125;delete[] arr;  // 释放数组arr = nullptr;​5.2 动态二维数组// 创建动态二维数组int rows = 3, cols = 4;int** matrix = new int*[rows];  // 创建行指针数组for (int i = 0; i &lt; rows; i++) &#123;    matrix[i] = new int[cols];  // 为每行创建列数组&#125;// 初始化for (int i = 0; i &lt; rows; i++) &#123;    for (int j = 0; j &lt; cols; j++) &#123;        matrix[i][j] = i * cols + j;    &#125;&#125;// 释放内存（逆序）for (int i = 0; i &lt; rows; i++) &#123;    delete[] matrix[i];&#125;delete[] matrix;matrix = nullptr;
 六、特殊指针类型
6.1 void指针（泛型指针）void print(void* data, char type) &#123;    switch(type) &#123;        case &#x27;i&#x27;:            cout &lt;&lt; *((int*)data) &lt;&lt; endl;            break;        case &#x27;f&#x27;:            cout &lt;&lt; *((float*)data) &lt;&lt; endl;            break;        case &#x27;c&#x27;:            cout &lt;&lt; *((char*)data) &lt;&lt; endl;            break;    &#125;&#125;int main() &#123;    int n = 5;    float f = 3.14;    char c = &#x27;A&#x27;;    print(&amp;n, &#x27;i&#x27;);    print(&amp;f, &#x27;f&#x27;);    print(&amp;c, &#x27;c&#x27;);    return 0;&#125;​6.2 const与指针int value = 10;int another = 20;// 指向常量的指针（指针指向的内容不能修改）const int* ptr1 = &amp;value;// *ptr1 = 20;  // 错误！不能通过ptr1修改valueptr1 = &amp;another;  // 但可以改变指针的指向// 常量指针（指针的指向不能修改）int* const ptr2 = &amp;value;*ptr2 = 30;       // 可以修改指向的值// ptr2 = &amp;another;  // 错误！不能改变指针的指向// 指向常量的常量指针const int* const ptr3 = &amp;value;// *ptr3 = 40;        // 错误！// ptr3 = &amp;another;  // 错误！​七、指针操作符 -&gt; 和 * 深度解析* 和 -&gt; 操作符对比1.1 基本概念区分#include &lt;iostream&gt;using namespace std;struct Point &#123;    int x;    int y;    void print() &#123;        cout &lt;&lt; &quot;(&quot; &lt;&lt; x &lt;&lt; &quot;, &quot; &lt;&lt; y &lt;&lt; &quot;)&quot; &lt;&lt; endl;    &#125;&#125;;int main() &#123;    Point p1 = &#123;10, 20&#125;;    Point* ptr = &amp;p1;    // 两种访问方式的对比    // 1. 使用 . 操作符（对象直接访问）    cout &lt;&lt; &quot;p1.x = &quot; &lt;&lt; p1.x &lt;&lt; endl;      // 10    p1.print();                              // (10, 20)    // 2. 使用 * 和 . 组合（指针解引用后访问）    cout &lt;&lt; &quot;(*ptr).x = &quot; &lt;&lt; (*ptr).x &lt;&lt; endl;  // 10    (*ptr).print();                              // (10, 20)    // 3. 使用 -&gt; 操作符（指针直接访问）    cout &lt;&lt; &quot;ptr-&gt;x = &quot; &lt;&lt; ptr-&gt;x &lt;&lt; endl;      // 10    ptr-&gt;print();                               // (10, 20)    return 0;&#125;​1.2 语法等价关系// 以下三种形式完全等价：ptr-&gt;member;     // 最简洁的指针访问方式(*ptr).member;   // 解引用后使用点操作符(*(ptr)).member; // 更明确的解引用​-&gt; 操作符详解2.1 -&gt; 操作符的工作原理class Student &#123;private:    string name;    int age;public:    Student(string n, int a) : name(n), age(a) &#123;&#125;    void display() &#123;        cout &lt;&lt; &quot;姓名: &quot; &lt;&lt; name &lt;&lt; &quot;, 年龄: &quot; &lt;&lt; age &lt;&lt; endl;    &#125;    void setName(string n) &#123;        name = n;    &#125;    string getName() const &#123;        return name;    &#125;&#125;;int main() &#123;    // 在栈上创建对象    Student s1(&quot;张三&quot;, 20);    s1.display();           // 对象直接使用 .    // 在堆上动态创建对象    Student* s2 = new Student(&quot;李四&quot;, 22);    // 访问成员函数    s2-&gt;display();          // 使用 -&gt;    s2-&gt;setName(&quot;王五&quot;);    cout &lt;&lt; &quot;新名字: &quot; &lt;&lt; s2-&gt;getName() &lt;&lt; endl;    // 访问数据成员（如果public）    // s2-&gt;name;  // 如果name是public才可以    delete s2;  // 记得释放内存    return 0;&#125;​2.2 为什么需要 -&gt; 操作符struct Node &#123;    int data;    Node* next;  // 指向下一个节点的指针    Node(int val) : data(val), next(nullptr) &#123;&#125;&#125;;int main() &#123;    // 创建链表节点    Node* head = new Node(1);    head-&gt;next = new Node(2);    head-&gt;next-&gt;next = new Node(3);  // 链式调用    // 遍历链表    Node* current = head;    while (current != nullptr) &#123;        cout &lt;&lt; current-&gt;data &lt;&lt; &quot; &quot;;        current = current-&gt;next;  // 移动到下一个节点    &#125;    // 对比：如果没有-&gt;操作符，代码会很繁琐    // (*head).next = new Node(2);    // (*(*head).next).next = new Node(3);    return 0;&#125;
 引用
 一、引用基础概念
1.1 什么是引用
引用是变量的别名，是一个已存在变量的另一个名字。
int var = 10;int&amp; ref = var;  // ref是var的引用（别名）
// 值传递 - 创建副本（不修改原数组）void bubbleSort(vector&lt;int&gt; arr) &#123;    // arr 是原数组的副本    // 修改这里的 arr 不会影响 main 中的原数组&#125;// 引用传递 - 直接操作原数组void bubbleSort(vector&lt;int&gt;&amp; arr) &#123;    // arr 是原数组的&quot;别名&quot;    // 修改这里的 arr 会影响 main 中的原数组&#125;
1.2 引用特性
· 必须初始化：引用在声明时必须初始化
· 不能重新绑定：一旦绑定到一个变量，就不能再绑定到其他变量
· 没有独立内存：引用与被引用变量共享同一内存地址
int x = 5;int y = 10;int&amp; r1 = x;  // 正确：声明时初始化// int&amp; r2;    // 错误：引用必须初始化r1 = 20;      // 修改x的值为20// r1 = y;    // 不是重新绑定，而是把y的值赋给xcout &lt;&lt; x &lt;&lt; endl;  // 20
 二、引用声明和初始化
2.1 基本类型引用
// 基本类型的引用int a = 42;int&amp; refA = a;         // refA是a的引用const int&amp; constRefA = a;  // 常引用double d = 3.14;double&amp; refD = d;char c = &#x27;A&#x27;;char&amp; refC = c;// 注意：引用类型必须与变量类型匹配// double&amp; refInt = a;  // 错误：类型不匹配
2.2 数组引用
// 一维数组引用int arr[5] = &#123;1, 2, 3, 4, 5&#125;;int (&amp;refArr)[5] = arr;  // 引用整个数组// 通过引用访问数组refArr[2] = 30;  // 修改arr[2]cout &lt;&lt; arr[2] &lt;&lt; endl;  // 30// 遍历数组引用for (int i = 0; i &lt; 5; i++) &#123;    cout &lt;&lt; refArr[i] &lt;&lt; &quot; &quot;;&#125;
2.3 指针的引用
int x = 100;int* ptr = &amp;x;int*&amp; refPtr = ptr;  // 指针的引用cout &lt;&lt; *ptr &lt;&lt; endl;     // 100cout &lt;&lt; *refPtr &lt;&lt; endl;  // 100，通过引用访问int y = 200;refPtr = &amp;y;  // 通过引用修改指针指向cout &lt;&lt; *ptr &lt;&lt; endl;  // 200
 三、引用与函数
3.1 引用作为函数参数（传引用）
// 通过引用修改实参void increment(int&amp; num) &#123;    num++;&#125;void swap(int&amp; a, int&amp; b) &#123;    int temp = a;    a = b;    b = temp;&#125;int main() &#123;    int x = 5;    cout &lt;&lt; &quot;原始值: &quot; &lt;&lt; x &lt;&lt; endl;  // 5    increment(x);    cout &lt;&lt; &quot;增加后: &quot; &lt;&lt; x &lt;&lt; endl;  // 6    int a = 10, b = 20;    cout &lt;&lt; &quot;交换前: a=&quot; &lt;&lt; a &lt;&lt; &quot;, b=&quot; &lt;&lt; b &lt;&lt; endl;    swap(a, b);    cout &lt;&lt; &quot;交换后: a=&quot; &lt;&lt; a &lt;&lt; &quot;, b=&quot; &lt;&lt; b &lt;&lt; endl;    return 0;&#125;
3.2 引用作为函数返回值
// 返回局部变量的引用是危险的！int&amp; badFunction() &#123;    int local = 42;  // 局部变量    return local;    // 危险！返回后local被销毁&#125;// 正确的用法：返回静态变量、全局变量或传入参数的引用int&amp; getElement(int arr[], int index) &#123;    return arr[index];  // 安全：返回数组元素的引用&#125;// 返回静态变量的引用int&amp; getCounter() &#123;    static int counter = 0;  // 静态变量，生命周期贯穿程序    counter++;    return counter;&#125;int main() &#123;    int array[5] = &#123;1, 2, 3, 4, 5&#125;;    // 修改数组元素    getElement(array, 2) = 100;    cout &lt;&lt; array[2] &lt;&lt; endl;  // 100    // 使用返回的引用    int&amp; countRef = getCounter();    cout &lt;&lt; &quot;计数器: &quot; &lt;&lt; countRef &lt;&lt; endl;  // 1    countRef = 50;  // 通过引用修改静态变量    cout &lt;&lt; &quot;修改后: &quot; &lt;&lt; getCounter() &lt;&lt; endl;  // 51    return 0;&#125;
3.3 常引用（const引用）
// 常引用：只读引用，不能通过它修改原变量int x = 10;const int&amp; constRef = x;// constRef = 20;  // 错误：不能通过常引用修改x = 20;            // 正确：可以直接修改原变量cout &lt;&lt; constRef &lt;&lt; endl;  // 20// 常引用的优势：可以绑定到临时对象int getValue() &#123;    return 42;&#125;int main() &#123;    // const int&amp; r1 = getValue();  // 正确：可以绑定到临时值    // int&amp; r2 = getValue();        // 错误：非常引用不能绑定到临时值    const int&amp; r = 100;  // 正确：常引用可以绑定到字面量    cout &lt;&lt; r &lt;&lt; endl;   // 100    return 0;&#125;
 四、引用与指针对比
4.1 语法对比
int value = 42;// 指针方式int* ptr = &amp;value;  // 取地址*ptr = 50;          // 解引用修改int x = *ptr;       // 解引用读取// 引用方式int&amp; ref = value;   // 直接绑定ref = 60;           // 直接修改int y = ref;        // 直接读取
4.2 关键区别
特性              指针                 引用初始化            可以不初始化           必须初始化重新赋值          可以指向不同变量        不能重新绑定空值              可以为null            ptr 不能为空内存占用          有自己的内存地址        与原始变量共享地址多级              可以有多级指针         只有一级引用运算符            需要*和-&gt;操作符        像普通变量一样使用
4.3 使用场景对比
// 场景1：函数参数传递void funcByPointer(int* p) &#123;    if (p != nullptr) &#123;  // 需要检查空指针        *p = 100;    &#125;&#125;void funcByReference(int&amp; r) &#123;    r = 100;  // 无需检查，引用不能为空&#125;// 场景2：返回多个值void getMinMaxByPointer(const int* arr, int size, int* min, int* max) &#123;    if (min != nullptr) *min = arr[0];    if (max != nullptr) *max = arr[0];    // ... 计算逻辑&#125;void getMinMaxByReference(const int* arr, int size, int&amp; min, int&amp; max) &#123;    min = arr[0];    max = arr[0];    // ... 计算逻辑&#125;
 五、引用高级用法
5.1 引用与const
// 四种组合int data = 10;// 1. 非常量引用（可以修改）int&amp; ref1 = data;ref1 = 20;  // 可以修改// 2. 常量引用（只读）const int&amp; ref2 = data;// ref2 = 30;  // 错误：不能通过ref2修改// 3. 对常量的引用（绑定到常量）const int constData = 40;// int&amp; ref3 = constData;  // 错误：不能绑定非常量引用到常量const int&amp; ref4 = constData;  // 正确// 4. 临时对象的引用// int&amp; ref5 = 50;  // 错误：不能绑定非常量引用到字面量const int&amp; ref6 = 50;  // 正确：常引用可以
5.2 引用在范围for循环中的应用
vector&lt;int&gt; vec = &#123;1, 2, 3, 4, 5&#125;;// 值传递：复制每个元素（效率低）for (int num : vec) &#123;    num *= 2;  // 只修改副本&#125;// vec内容不变：1, 2, 3, 4, 5// 引用传递：直接操作元素（效率高）for (int&amp; num : vec) &#123;    num *= 2;  // 修改原元素&#125;// vec内容变为：2, 4, 6, 8, 10// 常引用：只读访问for (const int&amp; num : vec) &#123;    // num *= 2;  // 错误：不能修改    cout &lt;&lt; num &lt;&lt; &quot; &quot;;&#125;
5.3 右值引用（C++11新特性）
// 左值引用：绑定到左值（有名字、有地址的对象）int x = 10;int&amp; lref = x;  // 左值引用// 右值引用：绑定到右值（临时对象、字面量）int&amp;&amp; rref1 = 42;         // 字面量是右值int&amp;&amp; rref2 = x + 5;      // 表达式结果是右值// 移动语义：高效转移资源所有权class MyString &#123;private:    char* data;public:    // 移动构造函数    MyString(MyString&amp;&amp; other) noexcept        : data(other.data) &#123;        other.data = nullptr;  // 置空原指针    &#125;    // 移动赋值运算符    MyString&amp; operator=(MyString&amp;&amp; other) noexcept &#123;        if (this != &amp;other) &#123;            delete[] data;            data = other.data;            other.data = nullptr;        &#125;        return *this;    &#125;&#125;;
 六、引用在类中的应用
6.1 成员引用
class Student &#123;private:    string&amp; nameRef;  // 引用成员public:    // 引用成员必须在构造函数的初始化列表中初始化    Student(string&amp; name) : nameRef(name) &#123;&#125;    void display() const &#123;        cout &lt;&lt; &quot;学生姓名: &quot; &lt;&lt; nameRef &lt;&lt; endl;    &#125;    void rename(string&amp; newName) &#123;        // nameRef = newName;  // 重新绑定？错误！        // 引用不能重新绑定，所以这里实际上不能修改    &#125;&#125;;int main() &#123;    string studentName = &quot;张三&quot;;    Student s(studentName);    s.display();    string newName = &quot;李四&quot;;    // s.rename(newName);  // 不能修改引用绑定    return 0;&#125;
6.2 返回*this（链式调用）
class Calculator &#123;private:    double result;public:    Calculator() : result(0) &#123;&#125;    // 返回引用支持链式调用    Calculator&amp; add(double value) &#123;        result += value;        return *this;  // 返回当前对象的引用    &#125;    Calculator&amp; subtract(double value) &#123;        result -= value;        return *this;    &#125;    Calculator&amp; multiply(double value) &#123;        result *= value;        return *this;    &#125;    double getResult() const &#123;        return result;    &#125;&#125;;int main() &#123;    Calculator calc;    // 链式调用    calc.add(10).subtract(3).multiply(2).add(5);    cout &lt;&lt; &quot;结果: &quot; &lt;&lt; calc.getResult() &lt;&lt; endl;  // 19    return 0;&#125;
 七、引用常见陷阱
7.1 返回局部变量的引用
// 错误示例int&amp; badExample() &#123;    int localVar = 100;  // 局部变量    return localVar;     // 返回局部变量的引用&#125;  // localVar被销毁，返回的引用变成悬空引用int main() &#123;    int&amp; ref = badExample();    // 危险！ref现在指向已销毁的内存    // cout &lt;&lt; ref &lt;&lt; endl;  // 未定义行为    return 0;&#125;
7.2 引用与指针的混淆
int x = 10;// 正确的引用用法int&amp; ref = x;// 常见的混淆错误// int&amp; ref = &amp;x;        // 错误：引用不需要取地址// int&amp; ref = *(&amp;x);     // 虽然能编译，但不推荐// 指针和引用的混合使用int* ptr = &amp;x;int&amp; refFromPtr = *ptr;  // 正确：解引用指针得到引用// 但这样更清晰int&amp; refDirect = x;
7.3 引用数组元素时的越界
int arr[5] = &#123;1, 2, 3, 4, 5&#125;;// 返回引用时要注意边界检查int&amp; getElement(int index) &#123;    // 危险：没有边界检查    return arr[index];&#125;// 改进版本int&amp; safeGetElement(int index) &#123;    if (index &gt;= 0 &amp;&amp; index &lt; 5) &#123;        return arr[index];    &#125;    // 返回静态变量或抛出异常    static int error = -1;    return error;&#125;
 递归
 一、什么是递归？
函数调用自身，把大问题拆成小问题，小问题再拆成更小的问题…
void func() &#123;    // ...    func();  // 👈 调用自己    // ...&#125;

 二、递归的两个核心要素

终止条件（必须要有！）

if (终止条件) &#123;    return;  // 不再调用自己&#125;
没有终止条件 = 死循环 → 栈溢出

递归调用（问题规模缩小）

func(更小的范围);  // 向终止条件靠近

 三、递归的执行过程
void func(int n) &#123;    if (n == 0) return;  // 终止条件    cout &lt;&lt; &quot;递: &quot; &lt;&lt; n;    func(n - 1);         // 递归调用    cout &lt;&lt; &quot;归: &quot; &lt;&lt; n;&#125;
调用 func(3)：
递: 3 → 递: 2 → 递: 1 → 触底                        ← 归: 1 ← 归: 2 ← 归: 3
阶段 动作  栈状态
递 向下调用 栈帧增加
归 向上返回 栈帧释放

 四、递归的核心认知（最难但也最重要）
✅ 每一层都是独立的函数调用！
void quickSort(arr, 0, 5) &#123;  // 第1层    int pi = partition(...); // pi=2    quickSort(arr, 0, 1);    // 👈 第2层    quickSort(arr, 3, 5);    // 👈 另一第2层&#125;
    每一层有       是否独立

参数    low, high     独立，值可能相同但互不影响
局部变量 i, pi         独立，同名但不是同一个
返回值   给上一层用，不是给下一层
递归不是代码在重复，是函数的每一层分身各干各的活！

 六、递归 vs 循环
维度 递归             循环
本质 函数调用自己    重复执行代码块
内存 每层新栈帧      共享同一栈帧
速度 略慢（调用开销）    快
代码 简洁，符合数学思维  直观
终止 必须显式条件    条件不成立即止
适用 树、分治、回溯    线性遍历
递归能做的循环都能做，但有些问题递归更自然（如快排、二叉树）。

 七、常见误区
误区1：递归是“代码复用”
真相：是函数复用，不是代码复用
误区2：下一层能用上一层的变量
真相：参数传值，不是共享变量
误区3：没创建新数组怎么递归
真相：用指针/索引画圈，不复制数据
quickSort(arr, low, pi - 1);  // 没创建新数组，只是移动指针！
误区4：返回值是给自己用
真相：返回值是给上一层用的！

 八、快排中的递归（完美案例）
void quickSort(vector&lt;int&gt;&amp; arr, int low, int high) &#123;    if (low &lt; high) &#123;                          // 1. 终止条件        int pi = partition(arr, low, high);    // 2. 当前层工作        quickSort(arr, low, pi - 1);           // 3. 递归左半（规模缩小）        quickSort(arr, pi + 1, high);          // 4. 递归右半（规模缩小）    &#125;&#125;
代码行 作用
if (low &lt; high) 终止条件：只剩0/1个元素就停
partition(…) 当前层：归位一个数
quickSort(…, pi-1) 递归：处理更小的左区间
quickSort(…, pi+1) 递归：处理更小的右区间
每层只归位一个数，n个元素需要n层递归（最坏情况）。
