 七、实用函数和算法
7.1 大小写转换
string str = &quot;Hello World&quot;;// 1. 转小写std::transform(str.begin(), str.end(), str.begin(),              [](unsigned char c)&#123; return std::tolower(c); &#125;);// &quot;hello world&quot;// 2. 转大写std::transform(str.begin(), str.end(), str.begin(),              [](unsigned char c)&#123; return std::toupper(c); &#125;);// &quot;HELLO WORLD&quot;// 3. C++23 有专门的函数// std::string s = std::to_upper(&quot;hello&quot;);
​
7.2 字符串分割
// C++没有内置split，需要自己实现vector&lt;string&gt; split(const string&amp; str, char delimiter) &#123;    vector&lt;string&gt; tokens;    size_t start = 0, end = 0;    while ((end = str.find(delimiter, start)) != string::npos) &#123;        tokens.push_back(str.substr(start, end - start));        start = end + 1;    &#125;    tokens.push_back(str.substr(start));    return tokens;&#125;// 使用string text = &quot;apple,banana,orange&quot;;vector&lt;string&gt; fruits = split(text, &#x27;,&#x27;);// fruits = &#123;&quot;apple&quot;, &quot;banana&quot;, &quot;orange&quot;&#125;
​
7.3 去除空白字符
string trim(const string&amp; str) &#123;    // 去除左边空白    size_t start = str.find_first_not_of(&quot; \\t\\n\\r&quot;);    if (start == string::npos) return &quot;&quot;;    // 去除右边空白    size_t end = str.find_last_not_of(&quot; \\t\\n\\r&quot;);    return str.substr(start, end - start + 1);&#125;string text = &quot;   Hello World   &quot;;string trimmed = trim(text);  // &quot;Hello World&quot;
​
 八、string 与流
8.1 stringstream
#include &lt;sstream&gt;#include &lt;string&gt;// 1. 字符串拼接（替代 sprintf）std::stringstream ss;ss &lt;&lt; &quot;姓名: &quot; &lt;&lt; &quot;张三&quot; &lt;&lt; &quot;, 年龄: &quot; &lt;&lt; 25;string info = ss.str();  // &quot;姓名: 张三, 年龄: 25&quot;// 2. 解析字符串string data = &quot;100 3.14 hello&quot;;std::stringstream parser(data);int n;double d;string s;parser &gt;&gt; n &gt;&gt; d &gt;&gt; s;  // n=100, d=3.14, s=&quot;hello&quot;// 3. 类型转换string strNum = &quot;123&quot;;int num;std::stringstream converter(strNum);converter &gt;&gt; num;  // num = 123
