 九、性能优化技巧
9.1 避免不必要的复制
// ❌ 不好：多次复制string process(string str) &#123;  // 值传递，复制一次    str += &quot; processed&quot;;       // 修改副本    return str;                // 返回时可能再复制&#125;// ✅ 好：使用引用string process(const string&amp; str) &#123;  // 引用，不复制    string result = str;             // 只在必要时复制    result += &quot; processed&quot;;    return result;&#125;// ✅ 更好：移动语义（C++11）string process(string&amp;&amp; str) &#123;       // 右值引用    str += &quot; processed&quot;;    return std::move(str);           // 移动，不复制&#125;​9.2 预分配内存// 情景：拼接多个字符串string result;result.reserve(1000);  // 预分配足够空间for (int i = 0; i &lt; 100; i++) &#123;    result += &quot;string&quot; + std::to_string(i) + &quot;, &quot;;&#125;// 避免了多次重新分配内存！
​
 十、常见陷阱
10.1 string 的生命周期
// 危险：返回局部string的c_str()const char* badFunction() &#123;    string local = &quot;Hello&quot;;    return local.c_str();  // ❌ local销毁后指针无效！&#125;// 正确：返回string对象string goodFunction() &#123;    string local = &quot;Hello&quot;;    return local;  // ✅ 返回值优化或移动&#125;
​
10.2 中文字符处理
string chinese = &quot;你好世界&quot;;  // UTF-8编码// ❌ 错误：下标访问得到的是字节，不是字符cout &lt;&lt; chinese[0] &lt;&lt; endl;  // 乱码！// ✅ 正确：需要特殊处理（C++20有更好支持）// 当前需要第三方库如ICU，或自己处理UTF-8// 获取字符数（不是字节数）size_t charCount = 0;for (char c : chinese) &#123;    if ((c &amp; 0xC0) != 0x80) charCount++;&#125;cout &lt;&lt; &quot;字符数: &quot; &lt;&lt; charCount &lt;&lt; endl;  // 
 函数重载

 一、什么是函数重载？
在同一个作用域内，定义多个同名函数，但参数列表不同。
// 三个同名函数，构成重载void print(int x);        // 1void print(double x);     // 2void print(string x);     // 3

 二、重载的判定规则
编译器根据「参数列表」区分，不看返回值！
✅ 可以重载（参数不同）
差异类型 示例
参数个数不同 void f(int) vs void f(int, int)
参数类型不同 void f(int) vs void f(double)
参数顺序不同 void f(int, double) vs void f(double, int)
❌ 不可以重载（编译器无法区分）
错误示例 原因
void f(int)  vs int f(int)        仅返回值不同
void f(int)  vs void f(const int) 顶层const被忽略
void f(int*) vs void f(int[])     数组退化为指针

 三、重载 vs 默认参数
特性 函数重载 默认参数
本质 多个不同函数 同一个函数
内存 多份代码 一份代码
调用 编译器静态匹配 编译器补全参数
灵活性 可做完全不同的事 只能省略尾部参数
// 重载：两个独立函数void log(string msg);        // 只记消息void log(string msg, int level); // 记消息+级别// 默认参数：一个函数void log(string msg, int level = 0);  // level可省略

 四、重载的匹配过程
编译器按优先级找最佳匹配：

精确匹配（类型完全相同）
提升匹配（char→int, float→double）
转换匹配（int→double, double→int）
用户定义转换

void f(int);    // 1void f(double); // 2f(&#x27;a&#x27;);  // char→int 精确提升，调用1f(3.14f); // float→double 提升，调用2

 五、常见用途

提供不同调用方式

// 快排：排整个数组 vs 排指定范围void quickSort(vector&lt;int&gt;&amp; arr);void quickSort(vector&lt;int&gt;&amp; arr, int low, int high);

处理不同类型

void show(int x);void show(double x);void show(string x);

可选参数组合

void connect(string host);void connect(string host, int port);void connect(string host, int port, bool ssl);

 六、常见陷阱
陷阱1：形参名不重要，类型才重要
void f(int a, int b);  // 这两个void f(int x, int y);  // 是同一个函数 ❌ 不是重载
陷阱2：const位置影响重载
void f(int* p);        // 1void f(const int* p);  // 2 ✅ 指向const，不同void f(int* const p);  // 与1相同 ❌ 指针自身const
陷阱3：引用与值
void f(int x);    // 1void f(int&amp; x);   // 2 ✅ 重载// 调用时 f(a) 会歧义！需要明确 f(&amp;a) 或 f(a) ？

 七、形象理解
重载就像「多义词」：
· “打”字 → 打人、打饭、打电话、打毛衣
· 同一个词，不同对象，不同动作
编译器就像聪明的读者，根据上下文（参数）自动理解你要表达哪个意思。
 const
 一、const 基础：创建常量
1.1 基本用法
// 1. 创建常量const int MAX_SIZE = 100;    // int常量const double PI = 3.14159;   // double常量const char NEWLINE = &#x27;\\n&#x27;;   // char常量// 2. 必须初始化// const int x;  // ❌ 错误！必须初始化const int y = 42;  // ✅ 正确// 3. 不可修改const int age = 25;// age = 30;  // ❌ 错误！不能修改常量
​
1.2 const vs #define（重要区别）
// ❌ C语言的宏（不要用！）#define MAX_USERS 100        // 没有类型，只是文本替换#define PI 3.14159// ✅ C++的const（推荐用！）const int MAX_USERS = 100;   // 有类型，类型安全const double PI = 3.14159;   // 有作用域，可调试// 宏的问题：#define SQUARE(x) x * xint result = SQUARE(2 + 3);  // 变成 2 + 3 * 2 + 3 = 11（错误！）// const函数没有这个问题
​
 二、const 与指针（重要！）
2.1 四种组合（必须掌握）
int value = 10;int other = 20;// 1. 指向常量的指针（指针指向的内容不能改）const int* ptr1 = &amp;value;  // 读作：ptr1指向const int// *ptr1 = 100;            // ❌ 错误！不能通过ptr1修改valueptr1 = &amp;other;             // ✅ 正确！指针本身可以指向别处// 2. 常量指针（指针本身不能指向别处）int* const ptr2 = &amp;value;  // 读作：const指针指向int*ptr2 = 100;               // ✅ 正确！可以修改指向的值// ptr2 = &amp;other;          // ❌ 错误！指针不能指向别处// 3. 指向常量的常量指针（都不能改）const int* const ptr3 = &amp;value;// *ptr3 = 100;            // ❌ 错误！// ptr3 = &amp;other;          // ❌ 错误！// 4. 非常量指针（都能改）int* ptr4 = &amp;value;*ptr4 = 100;               // ✅ 正确！ptr4 = &amp;other;             // ✅ 正确！
​
2.2 记忆技巧：从右向左读
const int* p1;       // 读：p1是指针，指向const int（内容不能改）int const* p2;       // 同上！const int* 和 int const* 等价int* const p3;       // 读：p3是const指针，指向int（指针不能改）const int* const p4; // 读：p4是const指针，指向const int（都不能改）
​
 三、const 与函数参数
3.1 保护传入的参数
// 场景1：值传递 + const（通常不需要）void func1(const int x) &#123;  // const在这里意义不大    // x = 10;  // ❌ 不能修改（但x本来就是副本）&#125;// 场景2：指针参数 + const（重要！）void printData(const int* data, int size) &#123;    for (int i = 0; i &lt; size; i++) &#123;        // data[i] = 0;  // ❌ 不能修改原始数据        cout &lt;&lt; data[i] &lt;&lt; &quot; &quot;;    &#125;&#125;// 场景3：引用参数 + const（最重要！最常用！）void processString(const string&amp; str) &#123;    // str.append(&quot;!&quot;);  // ❌ 不能修改    cout &lt;&lt; str.length() &lt;&lt; endl;  // ✅ 可以读取&#125;int main() &#123;    int arr[] = &#123;1, 2, 3, 4, 5&#125;;    string name = &quot;张三&quot;;    printData(arr, 5);       // 保证我不会修改你的数组    processString(name);     // 保证我不会修改你的字符串    return 0;&#125;
​
3.2 const引用避免拷贝（性能优化）
// ❌ 不好：拷贝整个大对象void printObject(MyClass obj) &#123;  // 调用拷贝构造函数    obj.display();&#125;// ✅ 好：const引用，没有拷贝void printObject(const MyClass&amp; obj) &#123;  // 不拷贝，不修改    obj.display();&#125;// 特别重要：string、vector等大对象一定要用const引用！void processBigData(const vector&lt;int&gt;&amp; data) &#123;    // 处理但不修改&#125;
​
 四、const 成员函数（类的核心特性）
4.1 基本概念
class BankAccount &#123;private:    double balance;    mutable int accessCount;  // 特殊：可以在const函数中修改public:    BankAccount(double b) : balance(b), accessCount(0) &#123;&#125;    // const成员函数：承诺不修改对象状态    double getBalance() const &#123;        accessCount++;        // ✅ mutable成员可以修改        return balance;       // ✅ 可以读取成员        // balance = 1000;    // ❌ 不能修改非mutable成员    &#125;    // 非const成员函数：可以修改对象    void deposit(double amount) &#123;        balance += amount;    // ✅ 可以修改    &#125;    // const对象只能调用const函数&#125;;int main() &#123;    BankAccount acc1(1000);      // 非const对象    const BankAccount acc2(2000); // const对象    acc1.getBalance();    // ✅ 可以    acc1.deposit(100);    // ✅ 可以    acc2.getBalance();    // ✅ 可以（getBalance是const）    // acc2.deposit(100); // ❌ 错误！const对象不能调用非const函数    return 0;&#125;
​
4.2 const重载
class Array &#123;private:    int* data;    int size;public:    // 非const版本：可以修改元素    int&amp; operator[](int index) &#123;        return data[index];  // 返回引用，可以修改    &#125;    // const版本：只读访问    const int&amp; operator[](int index) const &#123;        return data[index];  // 返回const引用，不能修改    &#125;&#125;;int main() &#123;    Array arr1;               // 非const对象    const Array arr2;         // const对象    arr1[0] = 100;            // ✅ 调用非const版本，可以修改    int x = arr2[0];          // ✅ 调用const版本，只能读取    // arr2[0] = 200;         // ❌ 错误！    return 0;&#125;
​
 五、const 与返回值
5.1 返回const值
class Point &#123;private:    int x, y;public:    Point(int x, int y) : x(x), y(y) &#123;&#125;    // 返回const引用，防止修改成员    const int&amp; getX() const &#123; return x; &#125;    const int&amp; getY() const &#123; return y; &#125;    // 不好的设计：返回非const引用    int&amp; badGetX() &#123; return x; &#125;  // 危险！外部可以修改x&#125;;int main() &#123;    Point p(10, 20);    // 好的设计：不能通过返回值修改    const int&amp; x = p.getX();    // x = 100;  // ❌ 错误！    // 不好的设计：可以修改私有成员！    int&amp; badX = p.badGetX();    badX = 999;  // ✅ 编译通过，但破坏了封装！    return 0;&#125;
​
5.2 返回const指针/引用
class Database &#123;private:    static Database* instance;public:    // 返回const指针，防止调用者修改单例    static const Database* getInstance() &#123;        return instance;    &#125;&#125;;// 使用：只能读取，不能修改const Database* db = Database::getInstance();// db-&gt;clear();  // ❌ 如果clear()不是const函数，就不能调用
​
 六、constexpr（C++11 编译时常量）
6.1 constexpr vs const
// const：运行时常量（可能编译时不知道值）const int size1 = getSize();  // 如果getSize()运行时才知道// constexpr：必须是编译时常量constexpr int size2 = 100;    // ✅ 编译时确定constexpr int size3 = size2 * 2;  // ✅ 编译时计算// constexpr函数：在编译时计算constexpr int square(int x) &#123;    return x * x;&#125;constexpr int val = square(10);  // 编译时计算，val=100// 数组大小必须用编译时常量int arr1[100];            // ✅ 字面量int arr2[size2];          // ✅ constexpr// int arr3[size1];       // ❌ 如果size1不是编译时常量
​
 七、mutable 关键字
7.1 特殊场景：const函数中修改
class Cache &#123;private:    mutable bool cacheValid;      // 缓存是否有效    mutable string cachedValue;   // 缓存的值    string realValue;             // 真实数据public:    // const函数中需要修改mutable成员    const string&amp; getValue() const &#123;        if (!cacheValid) &#123;            // 虽然是const函数，但可以修改mutable成员            cachedValue = realValue;  // 假设这里计算            cacheValid = true;        &#125;        return cachedValue;    &#125;&#125;;// 使用场景：缓存、访问计数、调试信息等
​
 八、实际应用指南
8.1 什么时候用const？
✅ 应该用const的场景：1. 函数参数（除非需要修改）   void func(const string&amp; str)  // ✅2. 成员函数（除非需要修改对象）   int getValue() const  // ✅3. 局部常量   const int max = 100;  // ✅4. 类成员（如果不应被修改）   const int id;  // ✅5. 返回值（如果不希望调用者修改）   const vector&lt;int&gt;&amp; getData()  // ✅
​
8.2 const的安全优势
// 示例：const如何防止错误class User &#123;    string name;public:    // 错误设计：返回非const引用    string&amp; getName() &#123; return name; &#125;    // 正确设计：返回const引用    const string&amp; getName() const &#123; return name; &#125;&#125;;void badCode(User&amp; user) &#123;    string&amp; name = user.getName();    name = &quot;黑客修改&quot;;  // ❌ 直接修改了私有成员！&#125;void goodCode(const User&amp; user) &#123;    const string&amp; name = user.getName();    // name = &quot;尝试修改&quot;;  // ❌ 编译错误！const保护&#125;

 Static
static 改变变量/函数的存储期和链接属性，不改变类型！
 三种不同用法

局部变量 + static（函数内使用）

void counter() &#123;    static int count = 0;  // 关键！    count++;    printf(&quot;调用次数: %d\\n&quot;, count);&#125;
作用：
· ✅ 变量只在第一次调用时初始化
· ✅ 生命周期延长到程序结束
· ✅ 存储位置：数据段(.data/.bss)，不在栈上！
· ✅ 保持上次调用结束时的值（有记忆！）


全局变量/函数 + static（文件作用域）

// file.cstatic int internal_var = 42;  // 只能在本文件使用static void helper() &#123;         // 只能在本文件调用    // ...&#125;
作用：
· ✅ 限制作用域到当前文件
· ✅ 避免命名冲突（内部链接）
· ✅ 信息隐藏（封装）
比喻： 公司内部文件（不外传）


C++类成员 + static

class MyClass &#123;public:    static int shared_count;  // 所有对象共享&#125;;int MyClass::shared_count = 0;
作用：
· ✅ 类级别变量，所有实例共享
· ✅ 无需创建对象即可访问
· ✅ 常用于计数器、配置等

 生动记忆法
普通变量 = 临时工
每天上班（函数调用）→ 分配工位（分配内存）每天下班（函数返回）→ 清空工位（释放内存）第二天是新开始（值不保留）
static变量 = 正式员工
入职时（第一次调用）→ 分配固定工位（数据段）每天下班（函数返回）→ 工位保留（内存不释放）第二天继续昨天的工作（值保留）

 关键理解点

static不改变数据类型！

static int x;      // 还是int类型，只是存储方式变了static char c;     // 还是char类型

初始化的特殊性

void func() &#123;    static int x = expensive_computation();  // 只计算一次！    // 后续调用直接使用计算好的值&#125;

 宏
 一、什么是宏？
宏是预处理器指令，在编译前进行文本替换。
#define PI 3.14159          // 定义常量#define SQUARE(x) ((x)*(x)) // 定义函数式宏
 二、基本用法

对象宏（常量替换）

#define MAX_SIZE 100        // 定义常量#define APP_NAME &quot;MyApp&quot;    // 字符串常量#define DEBUG_MODE          // 无值宏（条件编译用）int array[MAX_SIZE];        // 编译前替换为：int array[100];

函数式宏（带参数）

#define MIN(a, b) ((a) &lt; (b) ? (a) : (b))#define ABS(x) ((x) &lt; 0 ? -(x) : (x))int result = MIN(10, 20);   // 替换为：((10) &lt; (20) ? (10) : (20))

多行宏

#define LOG_ERROR(msg) \\    std::cerr &lt;&lt; &quot;ERROR: &quot; &lt;&lt; msg &lt;&lt; std::endl; \\    std::cerr &lt;&lt; &quot;File: &quot; &lt;&lt; __FILE__ &lt;&lt; std::endl; \\    std::cerr &lt;&lt; &quot;Line: &quot; &lt;&lt; __LINE__ &lt;&lt; std::endl;// 使用LOG_ERROR(&quot;File not found&quot;);
 三、特殊符号

字符串化（#）

#define STRINGIFY(x) #x     // 将参数转为字符串const char* str = STRINGIFY(hello);  // 变为 &quot;hello&quot;const char* str2 = STRINGIFY(3.14);  // 变为 &quot;3.14&quot;

连接符（##）

#define CONCAT(a, b) a##b   // 连接两个标识符int var1, var2, var3;int CONCAT(var, 1) = 10;    // 变为 int var1 = 10;int CONCAT(var, 2) = 20;    // 变为 int var2 = 20;

变长参数宏（C++11）

#define LOG(format, ...) \\    printf(&quot;[LOG] &quot; format, ##__VA_ARGS__)LOG(&quot;Value: %d, Name: %s\\n&quot;, 42, &quot;John&quot;);// 展开：printf(&quot;[LOG] &quot; &quot;Value: %d, Name: %s\\n&quot;, 42, &quot;John&quot;);
 四、预定义宏
cout &lt;&lt; &quot;文件: &quot; &lt;&lt; __FILE__ &lt;&lt; endl;     // 当前文件名cout &lt;&lt; &quot;行号: &quot; &lt;&lt; __LINE__ &lt;&lt; endl;     // 当前行号cout &lt;&lt; &quot;日期: &quot; &lt;&lt; __DATE__ &lt;&lt; endl;     // 编译日期cout &lt;&lt; &quot;时间: &quot; &lt;&lt; __TIME__ &lt;&lt; endl;     // 编译时间cout &lt;&lt; &quot;C++标准: &quot; &lt;&lt; __cplusplus &lt;&lt; endl;// 函数名宏（不同编译器）cout &lt;&lt; &quot;函数: &quot; &lt;&lt; __func__ &lt;&lt; endl;     // C++11标准cout &lt;&lt; &quot;函数: &quot; &lt;&lt; __FUNCTION__ &lt;&lt; endl; // GCC/MSVCcout &lt;&lt; &quot;函数: &quot; &lt;&lt; __PRETTY_FUNCTION__ &lt;&lt; endl; // GCC详细名
​
 内联函数
 一、什么是内联函数？

基本概念

内联函数是一种编译器优化技术，将函数调用替换为函数体代码，消除函数调用的开销。

关键特性

· 编译时行为：由编译器决定是否内联
· 空间换时间：代码膨胀换取执行速度
· 建议而非命令：inline 关键字只是建议
 二、三种写法

使用 inline 关键字

// 传统写法，在头文件中inline int max(int a, int b) &#123;    return (a &gt; b) ? a : b;&#125;

类内定义（隐式内联）

class Vector &#123;public:    double getX() const &#123; return x; &#125;  // 自动成为内联候选private:    double x;&#125;;

类外定义需显式声明

class Vector &#123;public:    double getX() const;  // 声明&#125;;inline double Vector::getX() const &#123;  // 定义时加 inline    return x;&#125;
 三、现代 C++ 的扩展

constexpr 函数（C++11+）

constexpr int factorial(int n) &#123;  // 编译时计算，隐式内联    return n &lt;= 1 ? 1 : n * factorial(n-1);&#125;constexpr int result = factorial(5);  // 编译时计算：120

consteval 函数（C++20）

consteval int square(int n) &#123;  // 必须编译时执行    return n * n;&#125;constexpr int val = square(10);  // OK，编译时计算// int runtime = square(x);      // 错误！x不是常量表达式

Lambda 表达式

auto main() -&gt; int &#123;    auto sum = [](int a, int b) -&gt; int &#123;        return a + b;    &#125;;  // Lambda通常被内联优化    int result = sum(5, 3);  // 很可能内联    return 0;&#125;
 析构函数
 一、什么是析构函数？
析构函数是对象被销毁时自动调用的特殊成员函数，用于清理资源。
class File &#123;    FILE* handle;public:    // 构造函数：获取资源    File(const char* filename) &#123;        handle = fopen(filename, &quot;r&quot;);        std::cout &lt;&lt; &quot;文件打开\\n&quot;;    &#125;    // 析构函数：释放资源    ~File() &#123;  // 注意：以 ~ 开头，与类名相同，无参数无返回值        if (handle) &#123;            fclose(handle);            std::cout &lt;&lt; &quot;文件关闭\\n&quot;;        &#125;    &#125;&#125;;
​
 二、基本语法和特性
语法：class MyClass &#123;public:    ~MyClass() &#123;  // 析构函数        // 清理代码    &#125;&#125;;​特性：class Example &#123;public:    // 1. 名称：~类名    ~Example() &#123; std::cout &lt;&lt; &quot;析构\\n&quot;; &#125;    // 2. 无参数    // ~Example(int x) &#123; &#125;  // ❌ 错误！不能有参数    // 3. 无返回值（连void都没有）    // ~Example() &#123; return 0; &#125;  // ❌ 错误！    // 4. 每个类只有一个析构函数    // ~Example(int) &#123; &#125;  // ❌ 不能重载！    // 5. 通常是publicprivate:    // ~Example() &#123; &#125;  // 可以private，但很少用&#125;;
​
 三、什么时候调用析构函数？
场景1：局部对象离开作用域void test() &#123;    File file(&quot;data.txt&quot;);  // 构造函数调用    // 使用文件...&#125;  // 离开作用域，自动调用 ~File()​场景2：动态对象被deleteFile* file = new File(&quot;data.txt&quot;);// 使用文件...delete file;  // 调用 ~File()​场景3：容器中的对象被销毁std::vector&lt;File&gt; files;files.push_back(File(&quot;1.txt&quot;));files.push_back(File(&quot;2.txt&quot;));// vector销毁时，所有元素的析构函数被调用​场景4：临时对象使用结束File(&quot;temp.txt&quot;).read();// 临时对象使用后立即销毁，调用 ~File()
​
 四、析构函数的实际应用
应用1：管理动态内存class Buffer &#123;private:    int* data;    size_t size;public:    // 构造函数：分配内存    Buffer(size_t sz) : size(sz) &#123;        data = new int[sz];        std::cout &lt;&lt; &quot;分配 &quot; &lt;&lt; sz &lt;&lt; &quot; 个int\\n&quot;;    &#125;    // 析构函数：释放内存    ~Buffer() &#123;        delete[] data;        std::cout &lt;&lt; &quot;释放内存\\n&quot;;    &#125;    // 禁止拷贝（避免双重释放）    Buffer(const Buffer&amp;) = delete;    Buffer&amp; operator=(const Buffer&amp;) = delete;&#125;;int main() &#123;    Buffer buf(100);  // 分配内存    // 使用buf...    return 0;  // 自动释放内存，无泄漏！&#125;​应用2：管理文件资源#include &lt;fstream&gt;#include &lt;string&gt;class LogFile &#123;private:    std::ofstream file;public:    LogFile(const std::string&amp; filename)        : file(filename, std::ios::app) &#123;        if (!file.is_open()) &#123;            throw std::runtime_error(&quot;无法打开日志文件&quot;);        &#125;        file &lt;&lt; &quot;=== 日志开始 ===\\n&quot;;    &#125;    ~LogFile() &#123;        if (file.is_open()) &#123;            file &lt;&lt; &quot;=== 日志结束 ===\\n&quot;;            file.close();        &#125;    &#125;    void write(const std::string&amp; message) &#123;        file &lt;&lt; message &lt;&lt; std::endl;    &#125;&#125;;int main() &#123;    try &#123;        LogFile log(&quot;app.log&quot;);        log.write(&quot;程序启动&quot;);        // ... 其他代码        log.write(&quot;处理数据&quot;);        // 程序结束或异常时，自动关闭文件并写结束标记    &#125; catch (const std::exception&amp; e) &#123;        std::cerr &lt;&lt; &quot;错误: &quot; &lt;&lt; e.what() &lt;&lt; std::endl;    &#125;    return 0;&#125;​应用3：管理网络连接class DatabaseConnection &#123;private:    void* connection;  // 假设的数据库连接public:    DatabaseConnection(const std::string&amp; url) &#123;        // 建立连接        std::cout &lt;&lt; &quot;连接数据库: &quot; &lt;&lt; url &lt;&lt; std::endl;        // connection = db_connect(url);    &#125;    ~DatabaseConnection() &#123;        // 断开连接        std::cout &lt;&lt; &quot;断开数据库连接\\n&quot;;        // db_disconnect(connection);    &#125;    void execute(const std::string&amp; query) &#123;        std::cout &lt;&lt; &quot;执行: &quot; &lt;&lt; query &lt;&lt; std::endl;        // db_execute(connection, query);    &#125;&#125;;
​
 五、RAII模式（析构函数的哲学）
RAII = Resource Acquisition Is Initialization（资源获取即初始化）
核心思想：对象的生命周期 = 资源的生命周期
// RAII的黄金法则：在构造函数中获取资源，在析构函数中释放资源
class RAII_Example &#123;    Resource* res;public:    RAII_Example() : res(new Resource()) &#123;  // 获取        // 如果这里失败，析构函数不会被调用    &#125;    ~RAII_Example() &#123; delete res; &#125;  // 保证释放&#125;;​RAII的威力：异常安全void risky_operation() &#123;    File file(&quot;data.txt&quot;);      // RAII：文件    DatabaseConnection db(&quot;...&quot;); // RAII：数据库连接    NetworkSocket socket(&quot;...&quot;);  // RAII：网络连接    // 如果这里抛出异常...    throw std::runtime_error(&quot;出错了！&quot;);    // 所有资源都会自动释放！    // 析构函数按创建相反的顺序调用：    // 1. ~NetworkSocket()    // 2. ~DatabaseConnection()    // 3. ~File()&#125;
​
 六、继承中的析构函数
规则1：虚析构函数class Base &#123;public:    virtual ~Base() &#123;  // ✅ 虚析构函数        std::cout &lt;&lt; &quot;~Base()\\n&quot;;    &#125;&#125;;class Derived : public Base &#123;    int* data;public:    Derived() : data(new int[100]) &#123;&#125;    ~Derived() override &#123;  // ✅ override 正确释放派生类资源        delete[] data;        std::cout &lt;&lt; &quot;~Derived()\\n&quot;;    &#125;&#125;;int main() &#123;    Base* ptr = new Derived();    delete ptr;  // ✅ 正确调用 ~Derived()，然后 ~Base()    return 0;&#125;​❌ 错误示例：没有虚析构函数class BadBase &#123;public:    ~BadBase() &#123; std::cout &lt;&lt; &quot;~BadBase()\\n&quot;; &#125;&#125;;class BadDerived : public BadBase &#123;    int* data;public:    BadDerived() : data(new int[100]) &#123;&#125;    ~BadDerived() &#123;        delete[] data;  // 可能不会被调用！        std::cout &lt;&lt; &quot;~BadDerived()\\n&quot;;    &#125;&#125;;int main() &#123;    BadBase* ptr = new BadDerived();    delete ptr;  // ❌ 只调用 ~BadBase()，内存泄漏！    return 0;&#125;
​
 八、析构函数的执行顺序
class Member &#123;public:    ~Member() &#123; std::cout &lt;&lt; &quot;~Member()\\n&quot;; &#125;&#125;;class Container &#123;    Member m1, m2;    int* data;public:    Container() : data(new int[10]) &#123;        std::cout &lt;&lt; &quot;Container()\\n&quot;;    &#125;    ~Container() &#123;        delete[] data;        std::cout &lt;&lt; &quot;~Container()\\n&quot;;        // 成员 m2, m1 自动析构    &#125;&#125;;int main() &#123;    Container c;    return 0;&#125;// 输出：// Container()// ~Container()// ~Member()// ~Member()
​
 九、常见错误和陷阱
错误1：忘记释放资源class BadClass &#123;    int* data;public:    BadClass() : data(new int[100]) &#123;&#125;    // ❌ 忘记写析构函数！    // 内存泄漏！&#125;;​错误2：双重释放class DoubleFree &#123;    int* data;public:    DoubleFree() : data(new int[10]) &#123;&#125;    ~DoubleFree() &#123;        delete[] data;    &#125;    // ❌ 拷贝构造函数导致两个对象共享同一内存    DoubleFree(const DoubleFree&amp; other) : data(other.data) &#123;&#125;    // 当两个对象析构时，delete[] 会被调用两次！&#125;;​错误3：部分构造问题class Problematic &#123;    int* ptr1;    int* ptr2;public:    Problematic() &#123;        ptr1 = new int[100];        throw std::runtime_error(&quot;构造失败！&quot;);  // ❌ 异常！        ptr2 = new int[100];  // 不会执行    &#125;    ~Problematic() &#123;        delete[] ptr1;  // 会被调用吗？        delete[] ptr2;    &#125;&#125;;// 如果构造函数抛出异常，析构函数不会被调用！// ptr1 的内存泄漏！
​
十、最佳实践
遵循RAII原则// ✅ 好：构造函数获取，析构函数释放class GoodResource &#123;    std::unique_ptr&lt;Resource&gt; res;public:    GoodResource() : res(acquire_resource()) &#123;&#125;    // 不需要写析构函数，unique_ptr自动处理&#125;;​基类总是用虚析构函数// ✅ 好：多态基类必须有虚析构函数class Base &#123;public:    virtual ~Base() = default;  // C++11 简洁写法&#125;;​使用智能指针避免手动管理// ✅ 好：让智能指针处理释放class Modern &#123;    std::unique_ptr&lt;int[]&gt; data;    std::shared_ptr&lt;Connection&gt; conn;public:    Modern()        : data(std::make_unique&lt;int[]&gt;(100)),          conn(std::make_shared&lt;Connection&gt;()) &#123;&#125;    // 不需要写析构函数！&#125;;​处理异常安全class ExceptionSafe &#123;    Resource* res1;    Resource* res2;public:    ExceptionSafe() : res1(nullptr), res2(nullptr) &#123;        res1 = new Resource();      // 可能失败        try &#123;            res2 = new Resource();  // 可能失败        &#125; catch (...) &#123;            delete res1;            // 清理部分构造的资源            throw;        &#125;    &#125;    ~ExceptionSafe() &#123;        delete res2;        delete res1;    &#125;&#125;;
 Lambda
 一、什么是Lambda？
Lambda是匿名函数对象，可以在需要函数的地方直接定义，不需要单独的函数声明。
// 传统函数int add(int a, int b) &#123; return a + b; &#125;// Lambda表达式auto add_lambda = [](int a, int b) &#123; return a + b; &#125;;
 二、Lambda的基本语法
[捕获列表](参数列表) -&gt; 返回类型 &#123; 函数体 &#125;​最简形式：[]()&#123;&#125;  // 什么都不做的最简lambda​实际例子：// 1. 无参数，无返回值auto sayHello = []() &#123;    std::cout &lt;&lt; &quot;Hello, World!&quot; &lt;&lt; std::endl;&#125;;// 2. 有参数，有返回值auto add = [](int a, int b) -&gt; int &#123;    return a + b;&#125;;// 3. 省略返回类型（编译器自动推导）auto multiply = [](double x, double y) &#123;    return x * y;  // 自动推导为double&#125;;// 4. 立即调用（IIFE）int result = [](int x) &#123; return x * x; &#125;(5);  // 25
​
 三、捕获列表详解
不捕获任何变量 []int x = 10, y = 20;auto func = []() &#123;    // ❌ 不能访问x, y    // return x + y;  // 错误！    return 0;&#125;;​值捕获 [var]int value = 42;auto copy_capture = [value]() &#123;    std::cout &lt;&lt; value &lt;&lt; std::endl;  // 42    // value = 100;  // ❌ 错误！不能修改（默认const）&#125;;value = 50;  // 修改原始变量copy_capture();  // 仍然输出42（捕获的是副本）​引用捕获 [&amp;var]int counter = 0;auto ref_capture = [&amp;counter]() &#123;    counter++;  // ✅ 可以修改原始变量    std::cout &lt;&lt; counter &lt;&lt; std::endl;&#125;;ref_capture();  // 输出1，counter变为1​隐式值捕获 [=]int a = 1, b = 2, c = 3;auto implicit_copy = [=]() &#123;    // 可以访问a, b, c的副本    return a + b + c;&#125;;​隐式引用捕获 [&amp;]int x = 10, y = 20;auto implicit_ref = [&amp;]() &#123;    x = 100;  // 修改原始x    y = 200;  // 修改原始y&#125;;implicit_ref();// 现在 x=100, y=200​混合捕获int a = 1, b = 2, c = 3;auto mixed = [a, &amp;b, c]() &#123;  // a值捕获，b引用捕获，c值捕获    // a是副本，b是引用，c是副本&#125;;auto mixed2 = [=, &amp;b]() &#123;     // 除了b是引用，其他都是值捕获    // a, c是副本，b是引用&#125;;auto mixed3 = [&amp;, a]() &#123;      // 除了a是值捕获，其他都是引用捕获    // a是副本，b, c是引用&#125;;​移动捕获（C++14） [var = std::move(var)]#include &lt;memory&gt;#include &lt;vector&gt;auto big_data = std::make_unique&lt;std::vector&lt;int&gt;&gt;();// 移动捕获：转移所有权，避免拷贝auto lambda = [data = std::move(big_data)]() &#123;    // data现在拥有原来的big_data    // big_data变为nullptr&#125;;
 五、Lambda的类型和存储
Lambda是唯一的类型auto lambda1 = []() &#123; return 1; &#125;;auto lambda2 = []() &#123; return 1; &#125;;// 每个lambda都有不同的类型static_assert(!std::is_same&lt;decltype(lambda1), decltype(lambda2)&gt;::value,              &quot;两个lambda类型不同！&quot;);​如何存储Lambda// 方法1：auto（最常见）auto lambda = []() &#123; return 42; &#125;;// 方法2：std::function（有类型擦除开销，但更灵活）#include &lt;functional&gt;std::function&lt;void()&gt; func = []() &#123; std::cout &lt;&lt; &quot;Hello&quot;; &#125;;// 方法3：函数指针（仅适用于无捕获的lambda）void (*func_ptr)() = []() &#123; std::cout &lt;&lt; &quot;无捕获lambda可转函数指针&quot;; &#125;;
 六、Lambda与函数对象的对比
传统函数对象（仿函数）：class Adder &#123;    int value;public:    Adder(int v) : value(v) &#123;&#125;    int operator()(int x) const &#123; return x + value; &#125;&#125;;Adder add5(5);int result = add5(10);  // 15​Lambda（更简洁）：int value = 5;auto add5 = [value](int x) &#123; return x + value; &#125;;int result = add5(10);  // 15
 七、Lambda的高级特性
可变Lambda（C++11） mutableint counter = 0;auto incrementer = [counter]() mutable &#123;    counter++;  // ✅ 现在可以修改捕获的副本    return counter;&#125;;std::cout &lt;&lt; incrementer() &lt;&lt; std::endl;  // 1std::cout &lt;&lt; incrementer() &lt;&lt; std::endl;  // 2std::cout &lt;&lt; &quot;原始counter: &quot; &lt;&lt; counter &lt;&lt; std::endl;  // 0（副本被修改，原值不变）​constexpr Lambda（C++17）// 可以在编译时计算的lambdaconstexpr auto square = [](int n) &#123; return n * n; &#125;;static_assert(square(5) == 25, &quot;编译时计算&quot;);constexpr int result = square(10);  // 编译时计算​模板Lambda（C++20）// 泛型lambda（C++14起）auto generic = [](auto a, auto b) &#123; return a + b; &#125;;// C++20：显式模板参数auto typed = []&lt;typename T&gt;(T a, T b) &#123; return a + b; &#125;;// 使用std::cout &lt;&lt; generic(1, 2) &lt;&lt; std::endl;     // 3std::cout &lt;&lt; generic(1.5, 2.5) &lt;&lt; std::endl; // 4.0std::cout &lt;&lt; typed(3, 4) &lt;&lt; std::endl;       // 7​在成员函数中使用 [this]class MyClass &#123;    int value = 42;public:    void process() &#123;        // 捕获this指针        auto lambda = [this]() &#123;            std::cout &lt;&lt; &quot;value: &quot; &lt;&lt; value &lt;&lt; std::endl;  // 访问成员            value = 100;  // 修改成员        &#125;;        lambda();    &#125;&#125;;
​
 八、常见陷阱和最佳实践
陷阱1：悬挂引用std::function&lt;int()&gt; create_bad_lambda() &#123;    int local = 42;    return [&amp;local]() &#123; return local; &#125;;  // ❌ 危险！返回后local被销毁&#125;// 正确：值捕获std::function&lt;int()&gt; create_good_lambda() &#123;    int local = 42;    return [local]() &#123; return local; &#125;;  // ✅ 安全&#125;​陷阱2：默认捕获的隐患class Resource &#123;    std::vector&lt;int&gt; data;public:    auto get_processor() &#123;        // ❌ 不好：隐式引用捕获[&amp;]可能捕获不想要的变量        return [&amp;]() &#123; return data.size(); &#125;;        // ✅ 更好：显式指定要捕获的        return [this]() &#123; return data.size(); &#125;;    &#125;&#125;;​最佳实践：// 1. 尽量使用值捕获，除非需要修改外部变量auto safe_lambda = [x]() &#123; return x * 2; &#125;;  // 值捕获// 2. 避免[&amp;]和[=]的隐式捕获，显式列出需要捕获的变量auto explicit_lambda = [&amp;counter, data]() &#123; /* ... */ &#125;;  // 明确// 3. 小心生命周期//    返回的lambda不要捕获局部变量的引用// 4. 简单逻辑用lambda，复杂逻辑考虑单独函数
 智能指针
 一、为什么需要智能指针？
传统指针的问题// ❌ 问题1：内存泄漏void bad_function() &#123;    int* ptr = new int(100);  // 分配内存    if (error_occurred) &#123;        return;  // ⚠️ 忘记delete！内存泄漏！    &#125;    delete ptr;  // 可能执行不到这里&#125;// ❌ 问题2：重复释放int* p1 = new int(10);int* p2 = p1;      // 两个指针指向同一内存delete p1;         // 释放一次delete p2;         // ⚠️ 再次释放！程序崩溃！// ❌ 问题3：空悬指针int* ptr = new int(20);delete ptr;        // 释放内存*ptr = 30;         // ⚠️ 访问已释放内存！未定义行为！​智能指针解决方案#include &lt;memory&gt;void safe_function() &#123;    auto ptr = std::make_unique&lt;int&gt;(100);  // 自动管理内存    if (error_occurred) &#123;        return;  // ✅ 自动释放内存，无泄漏！    &#125;    // ✅ 自动在作用域结束时释放&#125;
 二、三种智能指针对比
类型 所有权 复制行为 使用场景 性能unique_ptr 独占 禁止复制，可移动 单一所有者资源 ⭐⭐⭐⭐⭐ 最快shared_ptr 共享 引用计数，可复制 共享资源，多所有者 ⭐⭐⭐ 中等weak_ptr 弱引用 不增加引用计数 打破循环引用 ⭐⭐⭐⭐ 快
 三、unique_ptr（独占指针）
基本用法#include &lt;memory&gt;#include &lt;iostream&gt;class Resource &#123;public:    Resource() &#123; std::cout &lt;&lt; &quot;Resource acquired\\n&quot;; &#125;    ~Resource() &#123; std::cout &lt;&lt; &quot;Resource destroyed\\n&quot;; &#125;    void use() &#123; std::cout &lt;&lt; &quot;Using resource\\n&quot;; &#125;&#125;;int main() &#123;    // 创建unique_ptr（推荐make_unique）    auto ptr1 = std::make_unique&lt;Resource&gt;();  // C++14    ptr1-&gt;use();  // 像普通指针一样使用    // 传统方式（不推荐）    std::unique_ptr&lt;Resource&gt; ptr2(new Resource());    // unique_ptr不能复制，只能移动    auto ptr3 = std::move(ptr1);  // ptr1变为nullptr    if (!ptr1) &#123;        std::cout &lt;&lt; &quot;ptr1 is now empty\\n&quot;;    &#125;    // 自动在作用域结束时释放    return 0;&#125;​管理数组// 管理单个对象（默认）auto single = std::make_unique&lt;int&gt;(42);// 管理数组auto array = std::make_unique&lt;int[]&gt;(10);  // 10个int的数组array[0] = 1;array[1] = 2;// 传统方式（需要指定删除器）std::unique_ptr&lt;int[]&gt; arr(new int[5]&#123;1,2,3,4,5&#125;);​自定义删除器#include &lt;cstdio&gt;// 文件自动关闭auto file_closer = [](FILE* f) &#123;    if (f) &#123;        std::cout &lt;&lt; &quot;Closing file\\n&quot;;        fclose(f);    &#125;&#125;;std::unique_ptr&lt;FILE, decltype(file_closer)&gt;    filePtr(fopen(&quot;test.txt&quot;, &quot;r&quot;), file_closer);
 四、shared_ptr（共享指针）
基本用法#include &lt;memory&gt;#include &lt;iostream&gt;class SharedResource &#123;public:    SharedResource() &#123; std::cout &lt;&lt; &quot;Resource created\\n&quot;; &#125;    ~SharedResource() &#123; std::cout &lt;&lt; &quot;Resource destroyed\\n&quot;; &#125;&#125;;int main() &#123;    // 创建shared_ptr（推荐make_shared）    auto ptr1 = std::make_shared&lt;SharedResource&gt;();    &#123;        // 复制shared_ptr，引用计数+1        auto ptr2 = ptr1;  // 现在引用计数=2        std::cout &lt;&lt; &quot;Inside block, use_count: &quot;                  &lt;&lt; ptr1.use_count() &lt;&lt; std::endl;    &#125;  // ptr2销毁，引用计数-1    std::cout &lt;&lt; &quot;Outside block, use_count: &quot;              &lt;&lt; ptr1.use_count() &lt;&lt; std::endl;    return 0;  // 引用计数=0时自动释放&#125;​引用计数机制#include &lt;memory&gt;#include &lt;iostream&gt;int main() &#123;    auto sp1 = std::make_shared&lt;int&gt;(100);    std::cout &lt;&lt; &quot;sp1 use_count: &quot; &lt;&lt; sp1.use_count() &lt;&lt; std::endl;  // 1    auto sp2 = sp1;  // 复制构造，引用计数+1    std::cout &lt;&lt; &quot;sp1 use_count: &quot; &lt;&lt; sp1.use_count() &lt;&lt; std::endl;  // 2    std::cout &lt;&lt; &quot;sp2 use_count: &quot; &lt;&lt; sp2.use_count() &lt;&lt; std::endl;  // 2    sp1.reset();  // sp1放弃所有权，引用计数-1    std::cout &lt;&lt; &quot;sp2 use_count: &quot; &lt;&lt; sp2.use_count() &lt;&lt; std::endl;  // 1    // sp2离开作用域，引用计数=0，资源释放    return 0;&#125;​循环引用问题#include &lt;memory&gt;#include &lt;iostream&gt;class Node &#123;public:    std::shared_ptr&lt;Node&gt; next;    std::shared_ptr&lt;Node&gt; prev;    ~Node() &#123; std::cout &lt;&lt; &quot;Node destroyed\\n&quot;; &#125;&#125;;int main() &#123;    // 创建循环引用    auto node1 = std::make_shared&lt;Node&gt;();    auto node2 = std::make_shared&lt;Node&gt;();    node1-&gt;next = node2;  // node2引用计数=2    node2-&gt;prev = node1;  // node1引用计数=2    // 程序结束，但内存泄漏！    // node1引用计数=1 (node2的prev持有)    // node2引用计数=1 (node1的next持有)    std::cout &lt;&lt; &quot;End of main - memory leak!\\n&quot;;    return 0;&#125;
 五、weak_ptr（弱指针）
解决循环引用#include &lt;memory&gt;#include &lt;iostream&gt;class Node &#123;public:    std::shared_ptr&lt;Node&gt; next;    std::weak_ptr&lt;Node&gt; prev;  // 使用weak_ptr打破循环    ~Node() &#123; std::cout &lt;&lt; &quot;Node destroyed\\n&quot;; &#125;&#125;;int main() &#123;    auto node1 = std::make_shared&lt;Node&gt;();    auto node2 = std::make_shared&lt;Node&gt;();    node1-&gt;next = node2;      // node2引用计数=2    node2-&gt;prev = node1;      // node1引用计数=1（weak_ptr不增加计数）    // ✅ 没有内存泄漏！    std::cout &lt;&lt; &quot;node1 use_count: &quot; &lt;&lt; node1.use_count() &lt;&lt; std::endl;  // 1    std::cout &lt;&lt; &quot;node2 use_count: &quot; &lt;&lt; node2.use_count() &lt;&lt; std::endl;  // 2    return 0;  // 正确释放内存&#125;​weak_ptr基本操作#include &lt;memory&gt;#include &lt;iostream&gt;int main() &#123;    auto sp = std::make_shared&lt;int&gt;(42);    std::weak_ptr&lt;int&gt; wp = sp;  // 创建weak_ptr    // 检查资源是否还存在    if (!wp.expired()) &#123;        std::cout &lt;&lt; &quot;Resource still exists\\n&quot;;    &#125;    // 获取shared_ptr（如果资源还存在）    if (auto locked = wp.lock()) &#123;        std::cout &lt;&lt; &quot;Value: &quot; &lt;&lt; *locked &lt;&lt; std::endl;        std::cout &lt;&lt; &quot;use_count: &quot; &lt;&lt; locked.use_count() &lt;&lt; std::endl;  // 2    &#125;    sp.reset();  // 释放资源    if (wp.expired()) &#123;        std::cout &lt;&lt; &quot;Resource has been released\\n&quot;;    &#125;    return 0;&#125;
 六、性能考虑
make_shared vs new + shared_ptr// ✅ 推荐：make_shared（一次内存分配）auto sp1 = std::make_shared&lt;MyClass&gt;(args);// ❌ 不推荐：new + shared_ptr（两次内存分配）auto sp2 = std::shared_ptr&lt;MyClass&gt;(new MyClass(args));// 原因：// 1. make_shared：对象和控制块一次分配，更快// 2. 异常安全：make_shared保证原子性// 3. 内存局部性更好​何时使用哪种智能指针// 规则1：默认使用unique_ptr// 除非需要共享，否则都用unique_ptrauto config = std::make_unique&lt;Config&gt;();// 规则2：需要共享时用shared_ptrclass Connection &#123;    static std::shared_ptr&lt;Connection&gt; create() &#123;        return std::make_shared&lt;Connection&gt;();    &#125;&#125;;// 规则3：可能循环引用时用weak_ptrclass TreeNode &#123;    std::shared_ptr&lt;TreeNode&gt; child;    std::weak_ptr&lt;TreeNode&gt; parent;  // 父节点用weak_ptr&#125;;// 规则4：简单情况用值语义（不要过度使用智能指针）// 能用栈变量就不用堆分配std::vector&lt;int&gt; data;  // 直接用，不要vector&lt;unique_ptr&lt;int&gt;&gt;
 八、常见错误和陷阱
错误1：混用智能指针和裸指针// ❌ 错误：智能指针和裸指针混用int* raw_ptr = new int(100);std::shared_ptr&lt;int&gt; sp1(raw_ptr);std::shared_ptr&lt;int&gt; sp2(raw_ptr);  // ⚠️ 双重释放！// ✅ 正确：始终从make_shared开始auto sp1 = std::make_shared&lt;int&gt;(100);auto sp2 = sp1;  // 共享所有权​错误2：误用get()获取的裸指针auto sp = std::make_shared&lt;int&gt;(42);int* raw = sp.get();  // 获取内部裸指针// ❌ 错误：用raw指针创建新的智能指针std::shared_ptr&lt;int&gt; sp2(raw);  // ⚠️ 双重管理！// ❌ 错误：删除get()返回的指针delete sp.get();  // ⚠️ 智能指针会再次删除！// ✅ 正确：只用get()进行只读操作int value = *sp.get();  // 只读取值some_c_api(sp.get());   // 传给只使用不管理的C函数​错误3：错误的删除器// ❌ 错误：数组用默认删除器std::shared_ptr&lt;int&gt; arr(new int[10]);  // ⚠️ 应该用delete[]// ✅ 正确：数组用正确的删除器std::shared_ptr&lt;int[]&gt; arr(new int[10]);  // C++17// 或std::shared_ptr&lt;int&gt; arr(new int[10], std::default_delete&lt;int[]&gt;());
 九、最佳实践总结
黄金法则
// 1. 优先使用栈对象，其次unique_ptr，最后shared_ptrvoid process() &#123;    int local = 10;                    // 栈对象（最快）    auto unique = std::make_unique&lt;Resource&gt;();  // 独占资源    auto shared = std::make_shared&lt;SharedResource&gt;();  // 共享资源&#125;// 2. 使用make_unique/make_shared，不要用newauto ptr = std::make_unique&lt;MyClass&gt;();  // ✅auto ptr = std::unique_ptr&lt;MyClass&gt;(new MyClass());  // ❌// 3. 传递智能指针时考虑所有权语义void take_ownership(std::unique_ptr&lt;Data&gt; data);  // 接收所有权void share_ownership(std::shared_ptr&lt;Data&gt; data);  // 共享所有权void observe(std::weak_ptr&lt;Data&gt; data);  // 观察，不拥有void use_only(const Data* data);  // 只使用，不管理// 4. 避免循环引用，父节点用weak_ptrclass Node &#123;    std::shared_ptr&lt;Node&gt; child;    std::weak_ptr&lt;Node&gt; parent;  // 打破循环&#125;;
 链表
 一、核心概念：什么是链表？
链表 vs 数组（vector）内存对比
数组（vector）：连续内存
[元素1][元素2][元素3][元素4][    ]
↑ 所有元素挨在一起
链表：非连续内存（指针连接）
[数据1|next] → [数据2|next] → [数据3|next] → nullptr
↑             ↑               ↑
堆地址A       堆地址B          堆地址C（完全不连续！）
​
链表的本质：
// 每个节点 = 数据 + 指针
struct ListNode &#123;    int data;           // 数据部分    ListNode* next;     // 指向下一个节点的指针    ListNode(int val) : data(val), next(nullptr) &#123;&#125;&#125;;// 双向链表节点struct DoublyListNode &#123;    int data;    DoublyListNode* prev;  // 指向前一个节点    DoublyListNode* next;  // 指向后一个节点&#125;;
 二、STL中的链表（工作中实际用的）
std::list（双向链表）#include &lt;list&gt;#include &lt;iostream&gt;int main() &#123;    // 创建和初始化    std::list&lt;int&gt; lst1;                    // 空链表    std::list&lt;int&gt; lst2 = &#123;1, 2, 3, 4, 5&#125;;  // 初始值    std::list&lt;int&gt; lst3(10, 42);            // 10个42    // 🔥 核心操作（都是O(1)复杂度）    // 插入    lst1.push_front(0);       // 头部插入：0    lst1.push_back(1);        // 尾部插入：0→1    auto it = lst1.begin();    ++it;                     // 移动到第二个位置    lst1.insert(it, 99);      // 中间插入：0→99→1    // 删除    lst1.pop_front();         // 删除头部：99→1    lst1.pop_back();          // 删除尾部：99    lst1.erase(lst1.begin()); // 删除指定位置    // 访问（链表不能随机访问！）    std::cout &lt;&lt; &quot;第一个元素: &quot; &lt;&lt; lst2.front() &lt;&lt; std::endl;  // 1    std::cout &lt;&lt; &quot;最后一个元素: &quot; &lt;&lt; lst2.back() &lt;&lt; std::endl; // 5    // 遍历（只能用迭代器）    for (auto it = lst2.begin(); it != lst2.end(); ++it) &#123;        std::cout &lt;&lt; *it &lt;&lt; &quot; &quot;;  // 1 2 3 4 5    &#125;    // 或范围for    for (int val : lst2) &#123;        std::cout &lt;&lt; val &lt;&lt; &quot; &quot;;    &#125;    // 其他有用操作    lst2.sort();               // 排序 O(n log n)    lst2.unique();             // 删除连续重复元素    lst2.reverse();            // 反转链表 O(n)    // 合并链表（拼接，不是合并排序）    std::list&lt;int&gt; lstA = &#123;1, 2, 3&#125;;    std::list&lt;int&gt; lstB = &#123;4, 5, 6&#125;;    lstA.splice(lstA.end(), lstB);  // lstA: 1,2,3,4,5,6                                    // lstB变为空！    return 0;&#125;​std::forward_list（单向链表，C++11）#include &lt;forward_list&gt;#include &lt;iostream&gt;int main() &#123;    std::forward_list&lt;int&gt; flist = &#123;1, 2, 3, 4, 5&#125;;    // 单向链表特点：    // 1. 只有push_front，没有push_back！    // 2. 更省内存（每个节点少    // 遍历一样    for (int n : flist) &#123;        std::cout &lt;&lt; n &lt;&lt; &quot; &quot;;  // 0 1 2 3 4 5    &#125;    // 删除下一个元素（因为单向，要知道前一个节点）    auto it = flist.begin();    ++it;  // 指向第二个元素    flist.erase_after(flist.begin());  // 删除第二个元素    return 0;&#125;
 三、手动实现链表
单向链表基本实现class SimpleLinkedList &#123;private:    struct Node &#123;        int data;        Node* next;        Node(int val) : data(val), next(nullptr) &#123;&#125;    &#125;;    Node* head;    Node* tail;    int size;public:    SimpleLinkedList() : head(nullptr), tail(nullptr), size(0) &#123;&#125;    ~SimpleLinkedList() &#123;        // 必须手动释放所有节点！        Node* current = head;        while (current) &#123;            Node* next = current-&gt;next;            delete current;            current = next;        &#125;    &#125;    // 在尾部添加    void append(int val) &#123;        Node* newNode = new Node(val);        if (!head) &#123;            head = tail = newNode;        &#125; else &#123;            tail-&gt;next = newNode;            tail = newNode;        &#125;        size++;    &#125;    // 在头部添加    void prepend(int val) &#123;        Node* newNode = new Node(val);        newNode-&gt;next = head;        head = newNode;        if (!tail) tail = head;        size++;    &#125;    // 打印链表    void print() const &#123;        Node* current = head;        while (current) &#123;            std::cout &lt;&lt; current-&gt;data;            if (current-&gt;next) std::cout &lt;&lt; &quot; -&gt; &quot;;            current = current-&gt;next;        &#125;        std::cout &lt;&lt; &quot; -&gt; nullptr&quot; &lt;&lt; std::endl;    &#125;    // 反转链表（面试常考！）    void reverse() &#123;        Node* prev = nullptr;        Node* current = head;        tail = head;  // 头变尾        while (current) &#123;            Node* next = current-&gt;next;            current-&gt;next = prev;            prev = current;            current = next;        &#125;        head = prev;  // 新的头    &#125;    // 查找    bool contains(int val) const &#123;        Node* current = head;        while (current) &#123;            if (current-&gt;data == val) return true;            current = current-&gt;next;        &#125;        return false;    &#125;&#125;;// 使用int main() &#123;    SimpleLinkedList list;    list.append(1);    list.append(2);    list.append(3);    list.prepend(0);    list.print();  // 0 -&gt; 1 -&gt; 2 -&gt; 3 -&gt; nullptr    list.reverse();    list.print();  // 3 -&gt; 2 -&gt; 1 -&gt; 0 -&gt; nullptr    return 0;&#125;
 四、链表经典题（必须掌握）
反转链表ListNode* reverseList(ListNode* head) &#123;    ListNode* prev = nullptr;    ListNode* curr = head;    while (curr) &#123;        ListNode* next = curr-&gt;next;        curr-&gt;next = prev;        prev = curr;        curr = next;    &#125;    return prev;&#125;​检测环（快慢指针）bool hasCycle(ListNode* head) &#123;    if (!head || !head-&gt;next) return false;    ListNode* slow = head;    ListNode* fast = head-&gt;next;    while (slow != fast) &#123;        if (!fast || !fast-&gt;next) return false;        slow = slow-&gt;next;        fast = fast-&gt;next-&gt;next;    &#125;    return true;&#125;​合并两个有序链表ListNode* mergeTwoLists(ListNode* l1, ListNode* l2) &#123;    ListNode dummy(0);    ListNode* tail = &amp;dummy;    while (l1 &amp;&amp; l2) &#123;        if (l1-&gt;val &lt; l2-&gt;val) &#123;            tail-&gt;next = l1;            l1 = l1-&gt;next;        &#125; else &#123;            tail-&gt;next = l2;            l2 = l2-&gt;next;        &#125;        tail = tail-&gt;next;    &#125;    tail-&gt;next = l1 ? l1 : l2;    return dummy.next;&#125;​删除倒数第N个节点ListNode* removeNthFromEnd(ListNode* head, int n) &#123;    ListNode dummy(0);    dummy.next = head;    ListNode* fast = &amp;dummy;    ListNode* slow = &amp;dummy;    // fast先走n步    for (int i = 0; i &lt;= n; ++i) &#123;        fast = fast-&gt;next;    &#125;    // 一起走到fast到末尾    while (fast) &#123;        fast = fast-&gt;next;        slow = slow-&gt;next;    &#125;    // 删除slow的下一个节点    ListNode* to_delete = slow-&gt;next;    slow-&gt;next = slow-&gt;next-&gt;next;    delete to_delete;    return dummy.next;&#125;
 继承&amp;多态
 一、继承基础
三种继承方式
class Base &#123;public:    int public_var;protected:    int protected_var;private:    int private_var;&#125;;// 公有继承（最常用）：保持原有访问权限class PublicDerived : public Base &#123;    // public_var 仍是 public    // protected_var 仍是 protected    // private_var 不可访问&#125;;// 保护继承：public降级为protectedclass ProtectedDerived : protected Base &#123;    // public_var 变为 protected    // protected_var 仍是 protected    // private_var 不可访问&#125;;// 私有继承：全部变为privateclass PrivateDerived : private Base &#123;    // public_var 变为 private    // protected_var 变为 private    // private_var 不可访问&#125;;
构造和析构顺序
class Base &#123;public:    Base() &#123; cout &lt;&lt; &quot;Base构造&quot; &lt;&lt; endl; &#125;    ~Base() &#123; cout &lt;&lt; &quot;Base析构&quot; &lt;&lt; endl; &#125;&#125;;class Derived : public Base &#123;public:    Derived() &#123; cout &lt;&lt; &quot;Derived构造&quot; &lt;&lt; endl; &#125;    ~Derived() &#123; cout &lt;&lt; &quot;Derived析构&quot; &lt;&lt; endl; &#125;&#125;;int main() &#123;    Derived d;    return 0;&#125;// 输出：// Base构造// Derived构造// Derived析构// Base析构// 构造：先父后子，析构：先子后父​初始化列表调用父类构造class Base &#123;    int value;public:    Base(int v) : value(v) &#123;&#125;&#125;;class Derived : public Base &#123;    int extra;public:    // 必须初始化父类    Derived(int v, int e) : Base(v), extra(e) &#123;&#125;    // 错误：没有调用Base构造    // Derived(int v, int e) &#123; extra = e; &#125; ❌&#125;;
 二、函数重写与隐藏
函数隐藏（不是多态！）
class Base &#123;public:    void func() &#123; cout &lt;&lt; &quot;Base::func&quot; &lt;&lt; endl; &#125;&#125;;class Derived : public Base &#123;public:    void func(int x) &#123; cout &lt;&lt; &quot;Derived::func&quot; &lt;&lt; endl; &#125; // 隐藏了Base::func&#125;;int main() &#123;    Derived d;    d.func(1);      // ✅ 调用Derived::func    // d.func();    // ❌ 错误！Base::func被隐藏    d.Base::func(); // ✅ 指定调用父类的    return 0;&#125;​使用using恢复隐藏函数class Base &#123;public:    void func() &#123; cout &lt;&lt; &quot;Base::func&quot; &lt;&lt; endl; &#125;&#125;;class Derived : public Base &#123;public:    using Base::func;  // 恢复Base::func    void func(int x) &#123; cout &lt;&lt; &quot;Derived::func&quot; &lt;&lt; endl; &#125;&#125;;int main() &#123;    Derived d;    d.func();    // ✅ 现在可以调用    d.func(1);   // ✅ 也可以调用    return 0;&#125;
 三、多态基础
虚函数与overrideclass Animal &#123;public:    virtual void speak() &#123; cout &lt;&lt; &quot;动物叫&quot; &lt;&lt; endl; &#125;  // 虚函数    virtual void eat() = 0;  // 纯虚函数，抽象类    // 虚析构函数（多态基类必须！）    virtual ~Animal() &#123; cout &lt;&lt; &quot;~Animal&quot; &lt;&lt; endl; &#125;&#125;;class Dog : public Animal &#123;public:    void speak() override &#123;  // C++11: override确保正确重写        cout &lt;&lt; &quot;汪汪&quot; &lt;&lt; endl;    &#125;    void eat() override &#123;    // 必须实现纯虚函数        cout &lt;&lt; &quot;吃狗粮&quot; &lt;&lt; endl;    &#125;    ~Dog() override &#123; cout &lt;&lt; &quot;~Dog&quot; &lt;&lt; endl; &#125;&#125;;​多态使用示例void animalAction(Animal* animal) &#123;    animal-&gt;speak();  // 多态调用    animal-&gt;eat();&#125;int main() &#123;    Animal* zoo[] = &#123;new Dog(), new Cat(), new Bird()&#125;;    for (auto animal : zoo) &#123;        animalAction(animal);    &#125;    // 必须用delete，会调用正确的析构函数    for (auto animal : zoo) &#123;        delete animal;    &#125;    return 0;&#125;
 四、虚函数表（vtable）机制
vtable内存布局class Base &#123;public:    virtual void func1() &#123;&#125;    virtual void func2() &#123;&#125;    int data;&#125;;class Derived : public Base &#123;public:    void func1() override &#123;&#125;  // 覆盖    virtual void func3() &#123;&#125;   // 新增    int extra_data;&#125;;// vtable布局：// Base vtable:    [Base::func1][Base::func2]// Derived vtable: [Derived::func1][Base::func2][Derived::func3]//// 对象内存：// Base对象:     [vptr→Base vtable][data]// Derived对象:  [vptr→Derived vtable][data][extra_data]​虚函数调用过程Base* ptr = new Derived();ptr-&gt;func1();  // 运行时：// 1. 通过ptr找到对象// 2. 读取对象头部的vptr// 3. 通过vptr找到vtable// 4. 在vtable中找到func1的地址// 5. 调用Derived::func1()
 五、多重继承与虚继承
多重继承
class Printer &#123;public:    virtual void print() &#123; cout &lt;&lt; &quot;打印&quot; &lt;&lt; endl; &#125;&#125;;class Scanner &#123;public:    virtual void scan() &#123; cout &lt;&lt; &quot;扫描&quot; &lt;&lt; endl; &#125;&#125;;class MultiFunction : public Printer, public Scanner &#123;public:    void print() override &#123; cout &lt;&lt; &quot;多功能打印&quot; &lt;&lt; endl; &#125;    void scan() override &#123; cout &lt;&lt; &quot;多功能扫描&quot; &lt;&lt; endl; &#125;    void copy() &#123; print(); scan(); &#125;  // 新增功能&#125;;// 内存布局：有两个vptr！// [Printer vptr][Scanner vptr][MultiFunction数据]
钻石继承问题与虚继承
